import { useMemo, useState } from "react";
import { Link } from "react-router-dom";
import Header from "@/components/landing/Header";
import Footer from "@/components/landing/Footer";
import { useMarket } from "@/lib/MarketContext";
import { fmt } from "@/lib/parseItem";
import { Skeleton, SkeletonChart } from "@/components/ui/skeleton";
import { Reveal, RevealStagger, StaggerItem } from "@/components/landing/motion";
import {
  TrendingUp, TrendingDown, DollarSign, ShoppingCart, Percent,
  Search, Heart, Bell, ArrowUpRight,
} from "lucide-react";
import {
  ResponsiveContainer, BarChart, PieChart, LineChart,
  Bar, Pie, Line, XAxis, YAxis, Tooltip, Cell,
} from "recharts";

const COLORS = ["#10b981", "#3b82f6", "#f59e0b", "#ef4444", "#8b5cf6", "#06b6d4", "#ec4899"];

function SummaryCard({ label, value, sub, icon: Icon, trend }) {
  return (
    <div className="bg-white/[0.02] border border-white/10 rounded-lg p-5">
      <div className="flex items-center justify-between mb-2">
        <div className="text-[10px] uppercase tracking-wider text-zinc-500 font-mono">{label}</div>
        {Icon && <Icon className="w-4 h-4 text-zinc-500" />}
      </div>
      <div className="text-3xl font-heading font-bold tabular-nums">{value}</div>
      {sub && (
        <div className={`flex items-center gap-1 mt-1 text-[11px] ${trend === "up" ? "text-emerald-400" : trend === "down" ? "text-red-400" : "text-zinc-400"}`}>
          {trend === "up" && <TrendingUp className="w-3 h-3" />}
          {trend === "down" && <TrendingDown className="w-3 h-3" />}
          {sub}
        </div>
      )}
    </div>
  );
}

function ChartCard({ icon: Icon, title, children, className = "" }) {
  return (
    <div className={`bg-white/[0.02] border border-white/10 rounded-lg p-5 ${className}`}>
      <div className="flex items-center gap-2 mb-4">
        {Icon && <Icon className="w-4 h-4 text-emerald-400" />}
        <div className="text-[10px] uppercase tracking-wider text-zinc-500 font-mono">{title}</div>
      </div>
      {children}
    </div>
  );
}

export default function DashboardPage() {
  const { market, loading, error } = useMarket();
  const [chartRange, setChartRange] = useState("1d");

  const metrics = useMemo(() => {
    if (!market?.rows) return null;
    const stats = market.stats;
    const total = stats.totalItems;
    const priced = stats.pricedItems;
    const healthPct = Math.round((priced / total) * 100) || 0;
    const confidencePct = Math.round((stats.highConfidence / priced) * 100) || 0;
    const rising = stats.risingItems;

    const trendCounts = { up: 0, down: 0, stable: 0 };
    market.rows.forEach(r => {
      if (r.trend === "up") trendCounts.up++;
      else if (r.trend === "down") trendCounts.down++;
      else trendCounts.stable++;
    });

    const priceRanges = [
      { range: "<10k", min: 0, max: 10000, count: 0 },
      { range: "10k-100k", min: 10000, max: 100000, count: 0 },
      { range: "100k-1M", min: 100000, max: 1000000, count: 0 },
      { range: "1M-10M", min: 1000000, max: 10000000, count: 0 },
      { range: "10M-100M", min: 10000000, max: 100000000, count: 0 },
      { range: ">100M", min: 100000000, count: 0 },
    ];

    market.rows.forEach(row => {
      if (row.median > 0) {
        if (row.median < 10000) priceRanges[0].count++;
        else if (row.median < 100000) priceRanges[1].count++;
        else if (row.median < 1000000) priceRanges[2].count++;
        else if (row.median < 10000000) priceRanges[3].count++;
        else if (row.median < 100000000) priceRanges[4].count++;
        else priceRanges[5].count++;
      }
    });

    const volumeTrendsData = [
      { time: "1d", volume: 1200 },
      { time: "3d", volume: 1800 },
      { time: "7d", volume: 2500 },
      { time: "14d", volume: 3200 },
      { time: "30d", volume: 4500 },
    ];

    const markupBuckets = { low: 0, medium: 0, high: 0, veryHigh: 0, extreme: 0 };
    market.rows.forEach(row => {
      if (row.median <= 0 || row.iqrLow <= 0) return;
      const ratio = (row.median - row.iqrLow) / row.iqrLow;
      if (ratio < 0.10) markupBuckets.low++;
      else if (ratio < 0.25) markupBuckets.medium++;
      else if (ratio < 0.50) markupBuckets.high++;
      else if (ratio < 1.0) markupBuckets.veryHigh++;
      else markupBuckets.extreme++;
    });
    const markupAnalysisData = [
      { name: "<10%", value: markupBuckets.low },
      { name: "10-25%", value: markupBuckets.medium },
      { name: "25-50%", value: markupBuckets.high },
      { name: "50-100%", value: markupBuckets.veryHigh },
      { name: ">100%", value: markupBuckets.extreme },
    ];

    return {
      total, priced, healthPct, confidencePct, rising,
      trendCounts, priceDistributionData: priceRanges,
      volumeTrendsData, markupAnalysisData,
    };
  }, [market]);

  if (loading.market || !metrics) {
    return (
      <div className="min-h-screen bg-bg-base text-white">
        <Header />
        <main className="pt-32 pb-24">
          <div className="max-w-7xl mx-auto px-6 md:px-12 lg:px-16">
            <Skeleton className="h-4 w-32 mb-4" />
            <Skeleton className="h-12 w-96 mb-8" />
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
              {Array.from({ length: 4 }).map((_, i) => (
                <div key={i} className="bg-white/[0.02] border border-white/10 rounded-lg p-5 space-y-3">
                  <Skeleton className="h-3 w-20" />
                  <Skeleton className="h-8 w-24" />
                  <Skeleton className="h-3 w-16" />
                </div>
              ))}
            </div>
            <SkeletonChart />
          </div>
        </main>
        <Footer />
      </div>
    );
  }

  const {
    priceDistributionData, volumeTrendsData, markupAnalysisData,
    total, priced, healthPct, confidencePct, rising, trendCounts,
  } = metrics;

  return (
    <div className="min-h-screen bg-bg-base text-white">
      <Header />
      <main className="pt-32 pb-24">
        <div className="max-w-7xl mx-auto px-6 md:px-12 lg:px-16">
          <Reveal>
            <div className="font-mono text-[11px] uppercase tracking-[0.25em] text-emerald-400 mb-4">/ Market Dashboard</div>
            <h1 className="font-heading text-5xl lg:text-7xl tracking-tighter font-black leading-[0.95] mb-8">
              Market <span className="text-emerald-400">Health</span>
            </h1>
          </Reveal>

          {/* Quick actions toolbar */}
          <Reveal delay={0.05}>
            <div className="flex items-center gap-3 flex-wrap mb-8">
              <Link to="/lookup" className="inline-flex items-center gap-2 border border-white/15 hover:border-emerald-500/40 text-zinc-300 hover:text-emerald-400 font-bold uppercase tracking-[0.18em] text-[10px] px-4 py-2 rounded-sm transition-colors">
                <Search className="w-3.5 h-3.5" /> Look up item
              </Link>
              <Link to="/favorites" className="inline-flex items-center gap-2 border border-white/15 hover:border-emerald-500/40 text-zinc-300 hover:text-emerald-400 font-bold uppercase tracking-[0.18em] text-[10px] px-4 py-2 rounded-sm transition-colors">
                <Heart className="w-3.5 h-3.5" /> Favorites
              </Link>
              <Link to="/alerts" className="inline-flex items-center gap-2 border border-white/15 hover:border-emerald-500/40 text-zinc-300 hover:text-emerald-400 font-bold uppercase tracking-[0.18em] text-[10px] px-4 py-2 rounded-sm transition-colors">
                <Bell className="w-3.5 h-3.5" /> Alerts
              </Link>
            </div>
          </Reveal>

          {/* Summary cards */}
          <RevealStagger>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
              <StaggerItem>
                <SummaryCard label="Total Items" value={total} icon={ShoppingCart} />
              </StaggerItem>
              <StaggerItem>
                <SummaryCard label="Priced Items" value={priced} sub={`${healthPct}% coverage`} icon={DollarSign} />
              </StaggerItem>
              <StaggerItem>
                <SummaryCard label="High Confidence" value={`${confidencePct}%`} sub={`${market.stats.highConfidence} items`} icon={Percent} />
              </StaggerItem>
              <StaggerItem>
                <SummaryCard label="Rising Prices" value={rising} sub={`Updated ${market.stats.lastUpdated}`} trend="up" />
              </StaggerItem>
            </div>
          </RevealStagger>

          {/* Trend & Category */}
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 mb-8">
            <Reveal>
              <ChartCard icon={TrendingUp} title="Price Trends">
                <div className="grid grid-cols-3 gap-4">
                  <div className="text-center">
                    <div className="text-2xl font-bold text-emerald-400">{trendCounts.up}</div>
                    <div className="text-[11px] text-zinc-400 flex items-center justify-center gap-1 mt-1">
                      <TrendingUp className="w-3 h-3" /> Rising
                    </div>
                  </div>
                  <div className="text-center">
                    <div className="text-2xl font-bold text-red-400">{trendCounts.down}</div>
                    <div className="text-[11px] text-zinc-400 flex items-center justify-center gap-1 mt-1">
                      <TrendingDown className="w-3 h-3" /> Falling
                    </div>
                  </div>
                  <div className="text-center">
                    <div className="text-2xl font-bold text-zinc-300">{trendCounts.stable}</div>
                    <div className="text-[11px] text-zinc-400 mt-1">Stable</div>
                  </div>
                </div>
              </ChartCard>
            </Reveal>

            <Reveal delay={0.05}>
              <ChartCard icon={ShoppingCart} title="Category Breakdown">
                <div className="space-y-2">
                  {market.categoryBreakdown.slice(0, 5).map((c) => (
                    <div key={c.name} className="flex items-center gap-3">
                      <div className="w-2 h-2 rounded-full shrink-0" style={{ backgroundColor: c.color }} />
                      <div className="flex-1 text-sm font-mono truncate">{c.name}</div>
                      <div className="text-right shrink-0">
                        <div className="text-sm font-mono">{c.value}</div>
                        <div className="text-[10px] text-zinc-500">{c.pct}%</div>
                      </div>
                    </div>
                  ))}
                </div>
              </ChartCard>
            </Reveal>
          </div>

          {/* Charts */}
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 mb-8">
            <Reveal>
              <ChartCard icon={DollarSign} title="Price Distribution">
                <div className="h-64">
                  <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={priceDistributionData}>
                      <XAxis dataKey="range" tick={{ fill: "#9ca3af", fontSize: 10 }} />
                      <YAxis tick={{ fill: "#9ca3af", fontSize: 10 }} />
                      <Tooltip contentStyle={{ backgroundColor: "#1f2937", border: "none", borderRadius: "8px" }} labelStyle={{ color: "#d1d5db" }} itemStyle={{ color: "#d1d5db" }} />
                      <Bar dataKey="count" fill="#10b981" radius={[2, 2, 0, 0]} />
                    </BarChart>
                  </ResponsiveContainer>
                </div>
              </ChartCard>
            </Reveal>

            <Reveal delay={0.05}>
              <ChartCard icon={ShoppingCart} title="Volume Trends">
                <div className="flex gap-2 mb-4">
                  {["1d", "1w", "1m", "3m", "1y"].map((r) => (
                    <button
                      key={r}
                      onClick={() => setChartRange(r)}
                      className={`text-[10px] font-mono uppercase tracking-wider px-3 py-1 rounded-sm border transition-colors ${
                        chartRange === r
                          ? "border-emerald-500/50 text-emerald-400 bg-emerald-500/10"
                          : "border-white/10 text-zinc-500 hover:text-white"
                      }`}
                    >
                      {r}
                    </button>
                  ))}
                </div>
                <div className="h-64">
                  <ResponsiveContainer width="100%" height="100%">
                    <LineChart data={volumeTrendsData}>
                      <XAxis dataKey="time" tick={{ fill: "#9ca3af", fontSize: 10 }} />
                      <YAxis tick={{ fill: "#9ca3af", fontSize: 10 }} />
                      <Tooltip contentStyle={{ backgroundColor: "#1f2937", border: "none", borderRadius: "8px" }} labelStyle={{ color: "#d1d5db" }} itemStyle={{ color: "#d1d5db" }} />
                      <Line type="monotone" dataKey="volume" stroke="#10b981" strokeWidth={2} dot={false} />
                    </LineChart>
                  </ResponsiveContainer>
                </div>
              </ChartCard>
            </Reveal>
          </div>

          {/* Markup Analysis */}
          <Reveal>
            <ChartCard icon={Percent} title="Markup Analysis" className="mb-8">
              <div className="h-64">
                <ResponsiveContainer width="100%" height="100%">
                  <PieChart>
                    <Pie
                      data={markupAnalysisData}
                      cx="50%" cy="50%"
                      labelLine={false}
                      outerRadius={80}
                      fill="#8884d8"
                      dataKey="value"
                      label={({ name, percent }) => `${name} ${(percent * 100).toFixed(0)}%`}
                    >
                      {markupAnalysisData.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                      ))}
                    </Pie>
                    <Tooltip contentStyle={{ backgroundColor: "#1f2937", border: "none", borderRadius: "8px" }} labelStyle={{ color: "#d1d5db" }} itemStyle={{ color: "#d1d5db" }} />
                  </PieChart>
                </ResponsiveContainer>
              </div>
            </ChartCard>
          </Reveal>

          {/* Top Movers */}
          <Reveal>
            <ChartCard icon={ArrowUpRight} title="Top Movers">
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
                {market.topMovers.slice(0, 4).map((item) => (
                  <Link
                    key={item.key}
                    to={`/item/${item.key}`}
                    className="bg-white/[0.01] border border-white/10 rounded p-3 hover:bg-white/[0.04] transition-colors block"
                  >
                    <div className="text-sm font-mono truncate">{item.name}</div>
                    <div className="text-xs text-zinc-400 mt-1">{fmt(item.medianRaw)}</div>
                    <div className="text-[11px] mt-1">
                      <span className={item.trend === "rising" ? "text-emerald-400" : item.trend === "falling" ? "text-red-400" : "text-zinc-400"}>
                        {item.trend === "rising" ? "↑" : item.trend === "falling" ? "↓" : "—"} {item.trend}
                      </span>
                    </div>
                  </Link>
                ))}
              </div>
            </ChartCard>
          </Reveal>

          {error.market && (
            <div className="bg-red-500/10 border border-red-500/20 rounded-lg p-4 text-red-300 text-sm mt-8">
              {error.market}
            </div>
          )}
        </div>
      </main>
      <Footer />
    </div>
  );
}
